#include<bits/stdc++.h>
using namespace std;
long long n,m,r,a[50005],l,now,ans;
bool check(long long x)
{
	now=ans=0;
	for(int i=1;i<=n;i++)
	{
		if(now+x>a[i])
		{
			ans++;
		}
		else
		{
			now=a[i];
		}
	}
	return ans<=m;
}
int main()
{
	cin>>r>>n>>m;
	if(n==0){cout<<r;return 0;}
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	l=1;
	n++;
	a[n]=r;
//	for(int i=1;i<=5;i++)
//	{
//		cout<<check(i)<<"\n";
//	}
//	cout<<check(3)<<"\n";
	while(l<r)
	{
		long long mid=l+(r-l)/2;
		if(!check(mid))	r=mid;
		else	l=mid+1;
	}
	cout<<l-1;
	return 0;
}
